const handleDragEnd = (event, columns, boardId) => {
  const { active, over } = event;

  if (!over || active.id === over.id) {
    return;
  }

  const updateColumnOrderApi = (boardId, orderedIds) => {
    console.log(`API called for board ${boardId} with order:`, orderedIds);
  };

  const oldIndex = columns.findIndex(c => c._id === active.id);
  const newIndex = columns.findIndex(c => c._id === over.id);

  const orderedColumns = [...columns]; // Tạo bản sao
  const [movedColumn] = orderedColumns.splice(oldIndex, 1);
  orderedColumns.splice(newIndex, 0, movedColumn);

  const orderedColumnIds = orderedColumns.map(c => c._id);

  updateColumnOrderApi(boardId, orderedColumnIds);
};

