import { ObjectId } from 'mongodb';

const mockCollection = {
  _data: [{ _id: new ObjectId('60d5ecb3b3f4a3b3f4a3b3f4'), name: 'Test Board' }],
  async findOneAndUpdate(filter, update, options) {
    const doc = this._data.find(d => d._id.equals(filter._id));
    if (doc) {
      Object.assign(doc, update.$set);
      return options.returnDocument === 'after' ? { value: doc } : { value: null };
    }
    return { value: null };
  }
};

const boardModel = {
  update: async (id, data) => {
    try {
      const result = await mockCollection.findOneAndUpdate(
        { _id: new ObjectId(id) },
        { $set: data },
        { returnDocument: 'after' }
      );
      return result.value;
    } catch (error) {
      throw new Error(error);
    }
  }
};
